// src/pages/StartupPage.js

import React, { useState, useEffect } from "react";
import { useAuth } from "../context/AuthContext";
import { startupAPI } from "../services/api";
import AppLayout from "../components/AppLayout";

const DOMAINS = [
  "SaaS",
  "EdTech",
  "HealthTech",
  "FinTech",
  "E-Commerce",
  "AI/ML",
  "Web3",
  "CleanTech",
  "AgriTech",
  "Other",
];

export default function StartupPage() {
  const { user } = useAuth();

  const [startup, setStartup] = useState(null);
  const [startupId, setStartupId] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");
  const [goalInput, setGoalInput] = useState("");

  const [form, setForm] = useState({
    startupName: "",
    domain: "",
    targetAudience: "",
    budget: "",
    goals: [],
  });

  useEffect(() => {
    const load = async () => {
      try {
        const res = await startupAPI.get(user.id);
        const s = res.data.startup;

        setStartup(s);
        setStartupId(s._id);

        setForm({
          startupName: s.startupName || "",
          domain: s.domain || "",
          targetAudience: s.targetAudience || "",
          budget: s.budget || "",
          goals: s.goals || [],
        });
      } catch {
        // no startup yet
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [user.id]);

  const handleChange = (e) =>
    setForm({
      ...form,
      [e.target.name]: e.target.value,
    });

  const addGoal = () => {
    if (goalInput.trim() && form.goals.length < 8) {
      setForm({
        ...form,
        goals: [...form.goals, goalInput.trim()],
      });

      setGoalInput("");
    }
  };

  const removeGoal = (i) => {
    setForm({
      ...form,
      goals: form.goals.filter((_, idx) => idx !== i),
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    setSaving(true);
    setError("");
    setSuccess("");

    const payload = {
      ...form,
      budget: Number(form.budget) || 0,
    };

    try {
      if (startup) {
        await startupAPI.update(startupId, payload);
        setSuccess("Startup profile updated successfully!");
      } else {
        const res = await startupAPI.create({
          ...payload,
          userId: user.id,
        });

        setStartup(res.data.startup);
        setStartupId(res.data.startup._id);

        setSuccess("Startup profile created!");
      }

      setTimeout(() => {
        setSuccess("");
      }, 3000);
    } catch (err) {
      setError(
        err.response?.data?.message ||
          "Failed to save startup profile."
      );
    } finally {
      setSaving(false);
    }
  };

  return (
    <AppLayout
      title="Startup Profile"
      subtitle="Define your startup details — the AI uses this to personalise advice."
    >
      <div className="w-full max-w-6xl mx-auto px-6 py-6">

        {loading ? (
          <div className="flex justify-center items-center h-64">
            <div className="w-8 h-8 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin"></div>
          </div>
        ) : (
          <form
            onSubmit={handleSubmit}
            className="space-y-8"
          >

            {/* SUCCESS */}
            {success && (
              <div className="bg-green-500/10 border border-green-500/20 text-green-400 px-5 py-4 rounded-2xl">
                {success}
              </div>
            )}

            {/* ERROR */}
            {error && (
              <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-5 py-4 rounded-2xl">
                {error}
              </div>
            )}

            {/* BASIC INFO */}
            <div className="bg-[#081225] border border-white/5 rounded-3xl p-8 shadow-2xl">

              <h2 className="text-3xl font-bold text-white mb-8">
                Basic Info
              </h2>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">

                {/* Startup Name */}
                <div>
                  <label className="block text-sm text-gray-400 mb-2">
                    Startup Name
                  </label>

                  <input
                    type="text"
                    name="startupName"
                    value={form.startupName}
                    onChange={handleChange}
                    placeholder="e.g. EduAI Labs"
                    required
                    className="w-full bg-[#0f172a] border border-white/10 rounded-2xl px-4 py-3 text-white outline-none focus:border-blue-500"
                  />
                </div>

                {/* Domain */}
                <div>
                  <label className="block text-sm text-gray-400 mb-2">
                    Domain / Industry
                  </label>

                  <select
                    name="domain"
                    value={form.domain}
                    onChange={handleChange}
                    required
                    className="w-full bg-[#0f172a] border border-white/10 rounded-2xl px-4 py-3 text-white outline-none focus:border-blue-500"
                  >
                    <option value="">Select a domain</option>

                    {DOMAINS.map((d) => (
                      <option key={d} value={d}>
                        {d}
                      </option>
                    ))}
                  </select>
                </div>

                {/* Audience */}
                <div>
                  <label className="block text-sm text-gray-400 mb-2">
                    Target Audience
                  </label>

                  <input
                    type="text"
                    name="targetAudience"
                    value={form.targetAudience}
                    onChange={handleChange}
                    placeholder="e.g. College students"
                    required
                    className="w-full bg-[#0f172a] border border-white/10 rounded-2xl px-4 py-3 text-white outline-none focus:border-blue-500"
                  />
                </div>

                {/* Budget */}
                <div>
                  <label className="block text-sm text-gray-400 mb-2">
                    Monthly Budget (USD)
                  </label>

                  <input
                    type="number"
                    name="budget"
                    value={form.budget}
                    onChange={handleChange}
                    placeholder="e.g. 5000"
                    min="0"
                    className="w-full bg-[#0f172a] border border-white/10 rounded-2xl px-4 py-3 text-white outline-none focus:border-blue-500"
                  />
                </div>

              </div>
            </div>

            {/* GOALS */}
            <div className="bg-[#081225] border border-white/5 rounded-3xl p-8 shadow-2xl">

              <h2 className="text-3xl font-bold text-white mb-2">
                Goals & Milestones
              </h2>

              <p className="text-gray-500 mb-6">
                Add up to 8 goals. The AI will help you achieve them.
              </p>

              {/* ADD GOAL */}
              <div className="flex flex-col md:flex-row gap-4 mb-6">

                <input
                  type="text"
                  value={goalInput}
                  onChange={(e) =>
                    setGoalInput(e.target.value)
                  }
                  onKeyDown={(e) => {
                    if (e.key === "Enter") {
                      e.preventDefault();
                      addGoal();
                    }
                  }}
                  placeholder='e.g. "Launch MVP in 3 months"'
                  className="flex-1 bg-[#0f172a] border border-white/10 rounded-2xl px-4 py-3 text-white outline-none focus:border-blue-500"
                />

                <button
                  type="button"
                  onClick={addGoal}
                  disabled={
                    !goalInput.trim() ||
                    form.goals.length >= 8
                  }
                  className="bg-blue-600 hover:bg-blue-700 transition-all duration-200 text-white font-semibold px-8 py-3 rounded-2xl disabled:opacity-40"
                >
                  Add Goal
                </button>

              </div>

              {/* GOAL LIST */}
              {form.goals.length > 0 ? (
                <div className="flex flex-wrap gap-3">

                  {form.goals.map((g, i) => (
                    <div
                      key={i}
                      className="flex items-center gap-2 bg-[#0f172a] border border-white/10 rounded-2xl px-4 py-2 text-sm text-gray-300"
                    >
                      <span>{g}</span>

                      <button
                        type="button"
                        onClick={() => removeGoal(i)}
                        className="text-red-400 hover:text-red-300"
                      >
                        ×
                      </button>
                    </div>
                  ))}

                </div>
              ) : (
                <p className="text-gray-500 italic">
                  No goals added yet.
                </p>
              )}

            </div>

            {/* SUBMIT */}
            <button
              type="submit"
              disabled={saving}
              className="bg-blue-600 hover:bg-blue-700 transition-all duration-200 text-white font-semibold px-10 py-4 rounded-2xl shadow-lg disabled:opacity-50"
            >
              {saving
                ? "Saving..."
                : startup
                ? "Update Startup Profile →"
                : "Create Startup Profile →"}
            </button>

          </form>
        )}
      </div>
    </AppLayout>
  );
}
